import{_ as i,o as t,c as a,ag as o}from"./chunks/framework.BDReElpY.js";const m=JSON.parse('{"title":"Runtime and Tooling","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/runtime-and-tooling.md","filePath":"architecture/runtime-and-tooling.md"}'),n={name:"architecture/runtime-and-tooling.md"};function r(l,e,s,d,c,u){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="runtime-and-tooling" tabindex="-1">Runtime and Tooling <a class="header-anchor" href="#runtime-and-tooling" aria-label="Permalink to &quot;Runtime and Tooling&quot;">​</a></h1><p>The Vex repository is more than a compiler. The runtime and tools layer determines how code is linked, executed, tested, formatted, and surfaced in editors.</p><h2 id="runtime-layer" tabindex="-1">Runtime Layer <a class="header-anchor" href="#runtime-layer" aria-label="Permalink to &quot;Runtime Layer&quot;">​</a></h2><p>Runtime support lives primarily under <code>lib/runtime/</code>.</p><p>This layer includes infrastructure for:</p><ul><li>allocation and heap management</li><li>async and task runtime support</li><li>scheduler state</li><li>runtime symbols used by CLI execution paths</li><li>platform integration for native execution</li></ul><h2 id="jit-vs-no-jit" tabindex="-1">JIT vs No-JIT <a class="header-anchor" href="#jit-vs-no-jit" aria-label="Permalink to &quot;JIT vs No-JIT&quot;">​</a></h2><p>The repository distinguishes between JIT-oriented execution and no-JIT/subprocess execution.</p><p>One important documented constraint is that whole-runtime bitcode merge is intentionally disabled in JIT mode because runtime state is not yet structured for that safely.</p><p>Current safe model:</p><ul><li>AOT / subprocess mode can link runtime artifacts more traditionally</li><li>JIT mode relies on symbol registration rather than merging the entire runtime bitcode into the JIT module</li></ul><p>This is an architectural detail worth understanding when debugging “works in no-JIT but not in JIT” issues.</p><h2 id="cli-tooling" tabindex="-1">CLI Tooling <a class="header-anchor" href="#cli-tooling" aria-label="Permalink to &quot;CLI Tooling&quot;">​</a></h2><p><code>tools/vex-cli/</code> is the main developer-facing entry point.</p><p>Important commands:</p><ul><li><code>vex run</code></li><li><code>vex compile</code></li><li><code>vex test</code></li></ul><p>The CLI owns orchestration around:</p><ul><li>dependency resolution</li><li>compiler-driver invocation</li><li>linking</li><li>JIT/no-JIT selection</li><li>test discovery and execution</li></ul><h2 id="other-tooling" tabindex="-1">Other Tooling <a class="header-anchor" href="#other-tooling" aria-label="Permalink to &quot;Other Tooling&quot;">​</a></h2><p>The repository also contains:</p><ul><li><code>tools/vex-lsp/</code> for editor integration</li><li>formatter tooling</li><li>docs tooling and site generation</li></ul><p>These tools matter because they all depend on the same semantic model staying aligned with the compiler.</p><h2 id="why-this-layer-matters" tabindex="-1">Why This Layer Matters <a class="header-anchor" href="#why-this-layer-matters" aria-label="Permalink to &quot;Why This Layer Matters&quot;">​</a></h2><p>Many user-facing “language” issues are actually toolchain or runtime issues:</p><ul><li>link mode differences</li><li>symbol registration gaps</li><li>runtime state constraints</li><li>test-runner discovery assumptions</li><li>editor/compiler semantic drift</li></ul><p>Understanding this layer makes debugging much faster.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="/docs/references/vex-cli-reference">CLI Reference</a></li><li><a href="/docs/references/vex-test-reference">Test Reference</a></li><li><a href="/docs/architecture/compiler-pipeline">Compiler Pipeline</a></li></ul>',28)])])}const p=i(n,[["render",r]]);export{m as __pageData,p as default};
